281	static void convert_and_enqueue_scancode(SDL_Scancode code, int is_release)
282	{
283	    unsigned int ps2Code = sdl_to_ps2(code);
284	    if (ps2Code == 0xffffffff)
285	        return;
286	
287	    if (ps2Code > 0xff)
288	        enqueue_key((ps2Code >> 8) & 0xff);
289	
290	    if (is_release)
291	        enqueue_key(0xf0);
292	
293	    enqueue_key(ps2Code & 0xff);
294	}
