296	void poll_fb_window_event(void)
297	{
298	    SDL_Event event;
299	
300	    while (SDL_PollEvent(&event))
301	    {
302	        switch (event.type)
303	        {
304	            case SDL_QUIT:
305	                exit(0);
306	
307	            case SDL_KEYDOWN:
308	                convert_and_enqueue_scancode(event.key.keysym.scancode, 0);
309	                break;
310	
311	            case SDL_KEYUP:
312	                convert_and_enqueue_scancode(event.key.keysym.scancode, 1);
313	                break;
314	        }
315	    }
316	}
