334	                          fb_width * fb_height * 4), (int)(fb_width * 4)) != 0)
335	    {
336	        printf("SDL_Update_texture failed: %s\n", SDL_GetError());
337	        abort();
338	    }
339	
340	    if (SDL_RenderCopy(sdl_renderer, sdl_frame_buffer, NULL, NULL) != 0)
341	    {
342	        printf("SDL_Render_copy failed: %s\n", SDL_GetError());
343	        abort();
344	    }
345	
346	    SDL_RenderPresent(sdl_renderer);
347	    raise_interrupt(proc, INT_VGA_FRAME);
348	    clear_interrupt(proc, INT_VGA_FRAME);
