39	{
40	    CMD_GO_IDLE_STATE = 0,
41	    CMD_SEND_OP_COND = 1,
42	    CMD_SEND_IF_COND = 8,
43	    CMD_SET_BLOCKLEN = 16,
44	    CMD_READ_SINGLE_BLOCK = 17,
45	    CMD_WRITE_SINGLE_BLOCK = 24,
46	    CMD_APP_OP_COND = 41,
47	    CMD_APP_CMD = 55
48	};
49	
50	enum sd_state
51	{
52	    STATE_INIT_WAIT,
53	    STATE_IDLE,
54	    STATE_RECEIVE_COMMAND,
55	    STATE_READ_CMD_RESPONSE,
56	    STATE_READ_DATA_TOKEN,
57	    STATE_SEND_R1,
58	    STATE_SEND_R3,
59	    STATE_SEND_R7,
