67	static int block_fd = -1;
68	static enum sd_state current_state;
69	static uint32_t chip_select;
70	static uint32_t state_delay;
71	static uint32_t transfer_address;
72	static uint32_t transfer_count;
73	static uint32_t block_length;
74	static uint32_t init_clock_count;
75	static uint8_t command[SD_COMMAND_LENGTH];
76	static uint32_t command_length;
77	static char *block_buffer;
78	static bool in_idle_state = false;
79	static uint8_t check_pattern;
80	static uint8_t voltage;
81	static bool is_app_cmd = false;
82	
83	int open_sdmmc_device(const char *filename)
84	{
85	    struct stat fs;
86	    if (block_fd != -1)
87	        return 0;	// Already open
88	
89	    if (stat(filename, &fs) < 0)
90	    {
91	        perror("open_sdmmc_device: failed to stat block device file");
92	        return -1;
93	    }
94	
95	    block_fd = open(filename, O_RDWR);
96	    if (block_fd < 0)
97	    {
98	        perror("open_sdmmc_device: failed to open block device file");
99	        return -1;
100	    }
101	
102	    block_length = 512;
103	    block_buffer = malloc(block_length);
104	
105	    return 0;
106	}
107	
108	void close_sdmmc_device(void)
109	{
110	    assert(block_fd > 0);
111	    close(block_fd);
112	}
113	
114	static uint32_t read_little_endian(const uint8_t *values)
115	{
116	    return (uint32_t)((values[0] << 24) | (values[1] << 16) | (values[2] << 8)
117	        | values[3]);
118	}
119	
120	static void process_command(const uint8_t *command)
121	{
122	    if (is_app_cmd)
123	    {
124	        is_app_cmd = false;
125	        switch (command[0] & 0x3f)
126	        {
127	            case CMD_APP_OP_COND:
128	                current_state = STATE_SEND_R3;
129	                transfer_count = 0;
130	                in_idle_state = 0;
131	                break;
132	
133	            default:
134	                printf("sdmmc error: unknown command %02x\n", command[0]);
135	                exit(1);
136	        }
137	    }
138	    else
139	    {
140	        switch (command[0] & 0x3f)
141	        {
142	            case CMD_GO_IDLE_STATE:
143	                // If a virtual block device wasn't specified, don't initialize
144	                if (block_fd > 0)
145	                {
146	                    in_idle_state = true;
147	                    current_state = STATE_SEND_R1;
148	                }
149	
150	                break;
151	
152	            case CMD_SEND_OP_COND:
153	                current_state = STATE_SEND_R1;
154	                in_idle_state = false;
155	                break;
156	
157	            case CMD_SEND_IF_COND:
158	                current_state = STATE_SEND_R7;
159	                transfer_count = 0;
160	                voltage = command[3] & 0xf;
161	                check_pattern = command[4];
162	                break;
163	
164	            case CMD_SET_BLOCKLEN:
165	                if (in_idle_state)
166	                {
167	                    printf("CMD_SET_BLOCKLEN: card not ready\n");
168	                    exit(1);
169	                }
170	
171	                block_length = read_little_endian(command + 1);
172	                free(block_buffer);
173	                block_buffer = malloc(block_length);
174	                current_state = STATE_SEND_R1;
175	                break;
176	
177	            case CMD_READ_SINGLE_BLOCK:
178	                if (in_idle_state)
179	                {
180	                    printf("CMD_READ_SINGLE_BLOCK: card not ready\n");
181	                    exit(1);
182	                }
183	
184	                transfer_address = read_little_endian(command + 1) * block_length;
185	                if (lseek(block_fd, transfer_address, SEEK_SET) < 0)
186	                {
187	                    perror("CMD_READ_SINGLE_BLOCK: seek failed");
188	                    exit(1);
189	                }
190	
191	                if (read(block_fd, block_buffer, block_length) != block_length)
192	                {
193	                    printf("CMD_READ_SINGLE_BLOCK: read failed for block\n");
194	                    exit(1);
195	                }
196	
197	                transfer_count = 0;
198	                current_state = STATE_READ_CMD_RESPONSE;
199	                state_delay = next_random() & 0xf; // Wait a random amount of time
200	                break;
201	
202	            case CMD_WRITE_SINGLE_BLOCK:
203	                if (in_idle_state)
204	                {
205	                    printf("CMD_READ_SINGLE_BLOCK: card not ready\n");
206	                    exit(1);
207	                }
208	
209	                transfer_address = read_little_endian(command + 1) * block_length;
210	                transfer_count = 0;
211	                current_state = STATE_WRITE_CMD_RESPONSE;
212	                state_delay = next_random() & 0xf; // Wait a random amount of time
213	                break;
214	
215	            case CMD_APP_CMD:
216	                is_app_cmd = true;
217	                current_state = STATE_SEND_R1;
218	                break;
219	
220	            default:
221	                printf("sdmmc error: unknown command %02x\n", command[0]);
222	                exit(1);
223	        }
224	    }
225	}
226	
227	int transfer_sdmmc_byte(int value)
228	{
229	    int result = 0xff;
230	    switch (current_state)
231	    {
232	        case STATE_INIT_WAIT:
233	            init_clock_count += 8;
234	            if (!chip_select && init_clock_count < INIT_CLOCKS)
235	            {
236	                printf("sdmmc error: command posted before card initialized 1\n");
237	                exit(1);
238	            }
239	
240	        // Falls through
241	
242	        case STATE_IDLE:
243	            if (!chip_select && (value & 0xc0) == 0x40)
244	            {
245	                current_state = STATE_RECEIVE_COMMAND;
246	                command[0] = value;
247	                command_length = 1;
248	            }
249	
250	            break;
251	
252	        case STATE_RECEIVE_COMMAND:
253	            if (!chip_select)
254	            {
255	                command[command_length++] = value;
256	                if (command_length == SD_COMMAND_LENGTH)
257	                {
258	                    process_command(command);
259	                    command_length = 0;
260	                }
261	            }
262	
263	            break;
264	
265	        case STATE_SEND_R1:
266	            current_state = STATE_IDLE;
267	            result = (int) in_idle_state;
268	            break;
269	
270	        // 7.3.2.4
271	        case STATE_SEND_R3:
272	            result = 0;
273	            if (transfer_count == 0)
274	                result = (int) in_idle_state;
275	            else if (transfer_count == 4)
276	                current_state = STATE_IDLE;
277	
278	            transfer_count++;
279	            break;
280	
281	        // 7.3.2.6
282	        case STATE_SEND_R7:
283	            switch (transfer_count++)
284	            {
285	                case 0:
286	                    result = 1; // R1 response
287	                    break;
288	                case 1:
289	                case 2:
290	                    result = 0;
291	                    break;
292	                case 3:
293	                    result = voltage;
294	                    break;
295	                case 4:
296	                    result = check_pattern;
297	                    current_state = STATE_IDLE;
298	                    break;
299	            }
300	
301	            break;
302	
303	        case STATE_READ_CMD_RESPONSE:
304	            if (state_delay == 0)
305	            {
306	                current_state = STATE_READ_DATA_TOKEN;
307	                result = 0; // Signal ready
308	                state_delay = next_random() & 0xf;
309	            }
310	            else
311	                state_delay--;
312	
313	            break;
314	
315	        case STATE_READ_DATA_TOKEN:
316	            if (state_delay == 0)
317	            {
318	                current_state = STATE_READ_TRANSFER;
319	                result = DATA_TOKEN; // Send data token to start block
320	            }
321	            else
322	                state_delay--;
323	
324	            break;
325	
326	        case STATE_READ_TRANSFER:
327	            // This also adds a 2 byte checksum (which is ignored)
328	            if (transfer_count < block_length)
329	                result = block_buffer[transfer_count];
330	            else if (transfer_count == block_length + 1)
331	                current_state = STATE_IDLE;
332	
333	            transfer_count++;
334	            break;
335	
336	        case STATE_WRITE_CMD_RESPONSE:
337	            if (state_delay == 0)
338	            {
339	                current_state = STATE_WRITE_DATA_TOKEN;
340	                result = 0; // Signal ready
341	                state_delay = next_random() & 0xf;
342	            }
343	            else
344	                state_delay--;
345	
346	            break;
347	
348	        case STATE_WRITE_DATA_TOKEN:
349	            // Wait until we see the data token
350	            if (value == DATA_TOKEN)
351	                current_state = STATE_WRITE_TRANSFER;
352	
353	            break;
354	
355	        case STATE_WRITE_TRANSFER:
356	            // This also adds a 2 byte checksum (which is ignored)
357	            if (transfer_count < block_length)
358	                block_buffer[transfer_count] = value & 0xff;
359	            else if (transfer_count == block_length + 1)
360	                current_state = STATE_WRITE_DATA_RESPONSE;
361	
362	            transfer_count++;
363	            break;
364	
365	        case STATE_WRITE_DATA_RESPONSE:
366	            current_state = STATE_IDLE;
367	            result = 0x05;  // Data accepted
368	
369	            if (lseek(block_fd, transfer_address, SEEK_SET) < 0)
370	            {
371	                perror("CMD_READ_SINGLE_BLOCK: seek failed");
372	                exit(1);
373	            }
374	
375	            if (write(block_fd, block_buffer, block_length) != block_length)
376	            {
377	                printf("CMD_READ_SINGLE_BLOCK: write failed for block\n");
378	                exit(1);
379	            }
380	
381	            break;
382	    }
383	
384	    return result;
385	}
386	
387	void set_sdmmc_cs(int value)
388	{
389	    chip_select = value & 1;
390	}
